INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-03350', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作是社會工作方法之一，有關社區工作方法的特性，下列何者錯誤？', '["蘭尼報告書首先闡述社區組織是一種社會工作的干預方法，也是一種協助人民解決社區問題的 過程", "社區動力的形成，由社區居民個人所形成的個人間的團體動力", "社區工作直接面對社區中的領袖、菁英、志工及社區居民", "社區工作的主要技術，方案規劃、動員、會議、社會衝突管理及個案管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03351', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體發展的敘述，何者正確？', '["不同學者對團體發展階段有不同的主張，但大致可分為開始、工作和形成三大階段", "團體的發展是線性發展", "所有的團體都會經驗到親密期", "團體發展可能會前進間退化、循環、再前進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03352', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關規劃與設計團體活動時需考量的因素，下列何者錯誤？', '["需檢核單元目標是否符合團體目標", "需考量是否增加成員對個人議題認識的深度", "需依據團體成員的問題和需求，不需考量團體工作者的專長", "不同階段的團體，有不同的活動設計重點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03353', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關自助團體和治療團體的概念，下列敘述何者錯誤？', '["這兩種類型的團體各都聚集了擁有相同問題的成員，提供鼓勵支持，強調團體連結，並竭力爭 取改變", "自助團體專注於單一主題，而治療團體則考慮到更多的整體目標", "自助團體的典型小組長通常是擁有與其他成員不同問題的成員，治療團體小組長為受過良好團 體實務訓練的專業人士", "透過自助團體或治療團體，成員將未能表達的情感和想法抒發出來"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03354', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Kretzmunn與McKnight在「立基於資產社區發展」（asset-basedcommunitydevelopment）的定義， 下列何者錯誤？', '["資產：資產是社區中存在的各種事物，包括有意義的連結與關係等", "由地方定義：對資產的界定、活化與投資由社區定義", "關係驅動：人與人、人與組織等的關係網絡之建立被視為社會資本", "成果導向：以服務結果作為成功的標準，由正式機構評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03355', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關監督（monitoring）團體的評估，下列敘述何者錯誤？', '["監督是為了評估團體達成目的之程度", "自我監督方法紀錄，為成員自己行為或其他成員行為的次數、事件清單或自我問題排序", "問題導向紀錄，係由領導者針對團體問題和所設立目標進行記錄與檢視", "告知同意的錄音或錄影有助監督追蹤團體成員與團體過程的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03356', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列做法何者有助於催化成員更進一步參與團體？①活動目標具體明確  ②適時回饋與鼓勵彼', '["囊括所有人", "輪流發言  ⑤團體目標符合成員的需求", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03357', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在預估和評估團體與成員的功能時，採用不同蒐集資料的方法，下列敘述何者錯誤？', '["日誌是靠成員記憶，其正確性可能比圖解式紀錄低。為避免日誌的內容太特殊或太瑣碎，工作 人員必須清楚地建議成員記錄什麼資料", "工作人員可以透過自然觀察，看到整個團體的狀況，但有一個主要的限制是針對團體成員的行 為，團體的互動有時並不一定能提供做出適切預估的機會", "標準化的測量工具擁有信度和效度，可以適用在所有人身上，並對成員能力做出較為正確的評斷", "針對團體之外其他人對成員的觀察，工作人員要考慮提供資料者與成員的關係，要了解提供資 料者的動機，並確定是否有偏見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03358', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '領導者的價值系統會影響實務運作，下列何者最有可能發生影響、強迫或教化成員接受領導者或 機構價值觀的作法？', '["為居住庇護所的受暴婦女團體成員，規劃以返家或結束關係為主的團體", "提供家庭照顧者支持團體喘息服務資源", "新住民婦女團體討論各國坐月子文化", "非原住民籍團體領導者，向原住民課後照顧工作團體表現對部落照顧的看法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03359', 'social-worker', 'social-worker-moex-114-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者符合雙重關係危機最小化原則作法？①記錄下對任何雙重關係的討論與步驟  ②避免', '["有任何徵兆時先暫停成員繼續參與團體", "坦承澄清領導者 對關係考量的部分  ⑤處於雙重關係時，定期向其他專業者諮詢", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:18+00:00", "source_pdf_sha1": "f63d92231a8f", "answer_pdf_sha1": "96ffb2971074", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
